import React from 'react';

function WordCloud({ words }) {
  return (
    <div>
      <h2>Word Cloud</h2>
      {Object.entries(words || {}).map(([word, count]) => (
        <span
          key={word}
          style={{
            marginRight: '8px',
            fontSize: `${Math.min(count * 3 + 12, 28)}px`,
            fontWeight: 'bold',
            color: 'navy'
          }}
        >
          {word}
        </span>
      ))}
    </div>
  );
}

export default WordCloud;
